            array("exam_id" => "14", "enrolmentno" => "231939301", "scode" => "01IDST", "external" => "26"),
            array("exam_id" => "14", "enrolmentno" => "231939302", "scode" => "01IDST", "external" => "32"),
            array("exam_id" => "14", "enrolmentno" => "231939303", "scode" => "01IDST", "external" => "27"),
            array("exam_id" => "14", "enrolmentno" => "231939304", "scode" => "01IDST", "external" => "27"),
            array("exam_id" => "14", "enrolmentno" => "231939305", "scode" => "01IDST", "external" => "24"),
            array("exam_id" => "14", "enrolmentno" => "231939306", "scode" => "01IDST", "external" => "24"),
            array("exam_id" => "14", "enrolmentno" => "231939307", "scode" => "01IDST", "external" => "23"),
            array("exam_id" => "14", "enrolmentno" => "231939308", "scode" => "01IDST", "external" => "23"),
            array("exam_id" => "14", "enrolmentno" => "231939309", "scode" => "01IDST", "external" => "26"),
        );

        $sno = 0;
        $spreadsheet = new Spreadsheet();
        $sheet = $spreadsheet->getActiveSheet();

        $cell_sno = 1;
        $cell_count = 2;
        $sheet->setCellValue('A1', "S.No");
        $sheet->setCellValue('B1', "EnrolmentNo");
        $sheet->setCellValue('C1', "Scode");
        $sheet->setCellValue('D1', "Error");

        foreach ($details as $detail) {
            $sno++;
            $sheet->setCellValue('A'.$cell_count, $cell_sno);
            $sheet->setCellValue('B'.$cell_count, $detail["enrolmentno"]);
            $sheet->setCellValue('C'.$cell_count, $detail["scode"]);

            $candidate = Candidate::where("enrolmentno", $detail["enrolmentno"])->first();

            if(!is_null($candidate)) {
                $subjects = Subject::where("scode", $detail["scode"])->get();

                if($subjects->count() > 0) {
                    $application_count = 0;

                    foreach ($subjects as $subject) {
                        if(!is_null($subject)) {
                            $application = Application::where('exam_id', $detail["exam_id"])->where('candidate_id', $candidate->id)
                                ->where('subject_id', $subject->id)->first();

                            if(!is_null($application)) {
                                $application_count++;

                                $mark = Mark::where("application_id", $application->id)->first();

                                if (is_null($mark)) {
                                    $sheet->setCellValue('D'.$cell_count, "Mark");
                                } else {
                                    if ($detail["external"] == "Abs") {
                                        $mark->update([
                                            "external" => "Abs",
                                            "externalattendance_id" => 2,
                                            "externalresult_id" => 3
                                        ]);
                                    }
                                    else {
                                        if (intval($mark->application->subject->emax_marks) < intval($detail["external"])) {
                                            $sheet->setCellValue('D'.$cell_count, "Max Mark");
                                        } else {
                                            $mark->update([
                                                "externalattendance_id" => 1,
                                                "external" => intval($detail["external"])
                                            ]);

                                            if (intval($mark->application->subject->emin_marks) <= intval($detail["external"])) {
                                                $mark->update([
                                                    "externalresult_id" => 1
                                                ]);
                                            } else {
                                                $mark->update([
                                                    "externalresult_id" => 2
                                                ]);
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }

                    if($application_count == 0) {
                        $sheet->setCellValue('D'.$cell_count, "Application");
                    }
                }
                else {
                    $sheet->setCellValue('D'.$cell_count, "Subject Code");
                }
            }
            else {
                $sheet->setCellValue('D'.$cell_count, "Enrolment No.");
            }
            $cell_sno++;
            $cell_count++;
        }
        $writer = new Xlsx($spreadsheet);
        $writer->save('Ext_Marks-Mar2021-EVDL04.xlsx');
    }

